276.     /// <summary>
277.     /// Returns the number of words in a string, splitting on whitespace and common delimiters.
278.     /// </summary>
279.     /// <param name="input">The string to count words in.</param>
280.     /// <returns>The number of words found.</returns>
281.     public static int WordCount(this string input)
282.     {
